import React, { useEffect, useState } from 'react';
import api from '../../services/api';
import Loader from '../../components/Loader';
import ErrorMessage from '../../components/ErrorMessage';

const emptyDeliveredForm = { receiver_relation: 'titular', receiver_name: '', receiver_id: '' };

const RastreoFlexPage = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [communities, setCommunities] = useState([]);
  const [communityId, setCommunityId] = useState('');
  const [scanCode, setScanCode] = useState('');
  const [cart, setCart] = useState({ count: 0, items: [] });
  const [currentRoute, setCurrentRoute] = useState(null);
  const [stops, setStops] = useState([]);
  const [selectedStop, setSelectedStop] = useState(null);
  const [shipments, setShipments] = useState([]);
  const [depotReceivers, setDepotReceivers] = useState([]);
  const [deliveredForms, setDeliveredForms] = useState({});
  const [returnReceivers, setReturnReceivers] = useState({});

  const loadCurrent = async () => {
    const res = await api.get('/flex/api/routes/current');
    if (res.route) {
      setCurrentRoute(res.route);
      setStops(res.stops || []);
      setSelectedStop(null);
      setShipments([]);
    } else {
      setCurrentRoute(null);
      setStops([]);
    }
    return res;
  };

  const loadCommunities = async () => {
    const res = await api.get('/flex/api/communities');
    setCommunities(res.items || []);
    if (!communityId && res.items && res.items.length === 1) {
      setCommunityId(String(res.items[0].id));
    }
  };

  const loadCart = async (cid) => {
    const qs = cid ? `?community_id=${encodeURIComponent(cid)}` : '';
    const res = await api.get(`/flex/api/cart${qs}`);
    setCart({ count: res.count || 0, items: res.items || [] });
  };

  const initialLoad = async () => {
    setLoading(true);
    setError('');
    try {
      const current = await loadCurrent();
      if (!current.route) {
        await loadCommunities();
        await loadCart(communityId);
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    initialLoad();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (!currentRoute) {
      loadCart(communityId).catch(() => {});
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [communityId]);

  const handleScan = async (e) => {
    e.preventDefault();
    if (!scanCode.trim()) return;
    setLoading(true);
    setError('');
    try {
      await api.post('/flex/api/cart/scan', {
        raw_code: scanCode.trim(),
        source: 'manual',
        community_id: communityId || undefined,
      });
      setScanCode('');
      await loadCart(communityId);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleCartRemove = async (shipmentId) => {
    setLoading(true);
    setError('');
    try {
      await api.post('/flex/api/cart/remove', { shipment_id: shipmentId });
      await loadCart(communityId);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleStartRoute = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await api.post('/flex/api/route/start', { community_id: communityId || undefined });
      if (res.route) {
        setCurrentRoute(res.route);
        setStops(res.stops || []);
        setCart({ count: 0, items: [] });
      } else {
        await loadCurrent();
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectStop = async (stopId) => {
    setLoading(true);
    setError('');
    try {
      const res = await api.get(`/flex/api/stops/${stopId}`);
      setSelectedStop(res.stop || null);
      setShipments(res.shipments || []);
      setDepotReceivers(res.depot_receivers || []);
      const delivered = {};
      const returns = {};
      (res.shipments || []).forEach((sh) => {
        delivered[sh.id] = { ...emptyDeliveredForm };
        returns[sh.id] = '';
      });
      setDeliveredForms(delivered);
      setReturnReceivers(returns);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const updateDeliveredForm = (shipmentId, field, value) => {
    setDeliveredForms((prev) => ({
      ...prev,
      [shipmentId]: { ...(prev[shipmentId] || emptyDeliveredForm), [field]: value },
    }));
  };

  const handleShipmentAction = async (shipmentId, action) => {
    setLoading(true);
    setError('');
    try {
      const payload = { action, stop_id: selectedStop?.id };
      if (action === 'DELIVERED') {
        const form = deliveredForms[shipmentId] || emptyDeliveredForm;
        payload.receiver_relation = form.receiver_relation;
        payload.receiver_name = form.receiver_name;
        payload.receiver_id = form.receiver_id;
      }
      if (action === 'RETURN_TO_DEPOT_REQUESTED') {
        payload.return_to_user_id = returnReceivers[shipmentId] || undefined;
      }
      await api.post(`/flex/api/shipments/${shipmentId}/event`, payload);
      await handleSelectStop(selectedStop.id);
      await loadCurrent();
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleFinishRoute = async () => {
    if (!currentRoute?.id) return;
    setLoading(true);
    setError('');
    try {
      await api.post('/flex/api/route/finish', { route_id: currentRoute.id });
      await initialLoad();
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <h2>Cadete Flex</h2>
      {loading && <Loader />}
      <ErrorMessage error={error} />

      {!currentRoute && (
        <div>
          <div style={{ marginBottom: '10px' }}>
            <label>Comunidad: </label>
            <select value={communityId} onChange={(e) => setCommunityId(e.target.value)}>
              <option value="">General</option>
              {communities.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>

          <form onSubmit={handleScan} style={{ marginBottom: '10px' }}>
            <input type="text" value={scanCode} onChange={(e) => setScanCode(e.target.value)} placeholder="Escanear o pegar código..." required />
            <button type="submit" style={{ marginLeft: '5px' }}>Agregar al carrito</button>
          </form>

          <h3>Carrito ({cart.count || 0})</h3>
          {cart.items?.length ? (
            <ul style={{ listStyle: 'none', padding: 0 }}>
              {cart.items.map((item) => (
                <li key={item.shipment_id} style={{ marginBottom: '6px' }}>
                  {item.order_name || item.id_web || item.tracking_code} - {item.status}
                  <button type="button" onClick={() => handleCartRemove(item.shipment_id)} style={{ marginLeft: '8px' }}>Quitar</button>
                </li>
              ))}
            </ul>
          ) : (
            <p>No hay envíos cargados.</p>
          )}

          <button type="button" onClick={handleStartRoute} disabled={!cart.count}>Iniciar ruta</button>
        </div>
      )}

      {currentRoute && (
        <div style={{ display: 'flex' }}>
          <div style={{ width: '38%', marginRight: '12px' }}>
            <h3>Ruta #{currentRoute.id}</h3>
            <p>Comunidad: {currentRoute.community_name || '-'}</p>
            <button type="button" onClick={handleFinishRoute} style={{ marginBottom: '10px' }}>Finalizar ruta</button>
            <h4>Paradas</h4>
            <ul style={{ listStyle: 'none', padding: 0 }}>
              {stops.map((s) => (
                <li key={s.id} style={{ marginBottom: '5px' }}>
                  <button type="button" onClick={() => handleSelectStop(s.id)}>
                    #{s.sequence} - {s.address_text} ({s.count}) [{s.state}]
                  </button>
                </li>
              ))}
            </ul>
          </div>
          <div style={{ flex: 1 }}>
            {selectedStop ? (
              <div>
                <h3>Parada #{selectedStop.sequence}</h3>
                <p>{selectedStop.address_text}</p>
                {shipments.length ? shipments.map((sh) => {
                  const delivered = deliveredForms[sh.id] || emptyDeliveredForm;
                  return (
                    <div key={sh.id} style={{ border: '1px solid #ddd', padding: '10px', marginBottom: '10px' }}>
                      <div><strong>{sh.order_name || sh.id_web || sh.tracking_code}</strong> - {sh.status}</div>
                      <div style={{ marginTop: '8px' }}>
                        <div><strong>Entrega</strong></div>
                        <input type="text" value={delivered.receiver_name} onChange={(e) => updateDeliveredForm(sh.id, 'receiver_name', e.target.value)} placeholder="Nombre recibe" />
                        <input type="text" value={delivered.receiver_id} onChange={(e) => updateDeliveredForm(sh.id, 'receiver_id', e.target.value)} placeholder="Documento" style={{ marginLeft: '5px' }} />
                        <input type="text" value={delivered.receiver_relation} onChange={(e) => updateDeliveredForm(sh.id, 'receiver_relation', e.target.value)} placeholder="Relación" style={{ marginLeft: '5px' }} />
                        <button type="button" onClick={() => handleShipmentAction(sh.id, 'DELIVERED')} style={{ marginLeft: '5px' }}>Entregado</button>
                      </div>
                      <div style={{ marginTop: '8px' }}>
                        <div><strong>Devolución a depósito</strong></div>
                        <select value={returnReceivers[sh.id] || ''} onChange={(e) => setReturnReceivers((prev) => ({ ...prev, [sh.id]: e.target.value }))}>
                          <option value="">Seleccionar receptor</option>
                          {depotReceivers.map((u) => (
                            <option key={u.id} value={u.id}>{u.label}</option>
                          ))}
                        </select>
                        <button type="button" onClick={() => handleShipmentAction(sh.id, 'RETURN_TO_DEPOT_REQUESTED')} style={{ marginLeft: '5px' }}>Devolver</button>
                      </div>
                    </div>
                  );
                }) : <p>No hay envíos en esta parada.</p>}
              </div>
            ) : (
              <p>Seleccioná una parada.</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default RastreoFlexPage;
